package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testIsEscapeCharacterSetWhenEscapeCharacterIsNull() throws Exception {
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        // Using reflection to set escapeCharacter to null explicitly
        Field escapeCharacterField = CSVFormat.class.getDeclaredField("escapeCharacter");
        escapeCharacterField.setAccessible(true);
        // Because escapeCharacter is final, we must remove final modifier via reflection
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(escapeCharacterField, escapeCharacterField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        escapeCharacterField.set(csvFormat, null);

        boolean result = csvFormat.isEscapeCharacterSet();

        assertFalse(result);
    }

    @Test
    void testIsEscapeCharacterSetWhenEscapeCharacterIsNotNull() throws Exception {
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        // Using reflection to set escapeCharacter to a non-null Character
        Field escapeCharacterField = CSVFormat.class.getDeclaredField("escapeCharacter");
        escapeCharacterField.setAccessible(true);
        // Remove final modifier
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(escapeCharacterField, escapeCharacterField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        escapeCharacterField.set(csvFormat, '\\');

        boolean result = csvFormat.isEscapeCharacterSet();

        assertTrue(result);
    }
}
